# Non-blocking scheduler pattern — replace all time.sleep() with this
import time

class Scheduler:
    """Run functions at intervals without blocking."""
    def __init__(self):
        self._tasks = []

    def every(self, interval_ms, callback):
        """Register callback to run every interval_ms milliseconds."""
        self._tasks.append({
            'interval': interval_ms,
            'callback': callback,
            'next_run': time.ticks_ms()
        })

    def run_once(self, delay_ms, callback):
        """Run callback once after delay_ms."""
        self._tasks.append({
            'interval': delay_ms,
            'callback': callback,
            'next_run': time.ticks_add(time.ticks_ms(), delay_ms),
            'once': True
        })

    def tick(self):
        """Call this in your main loop as fast as possible."""
        now = time.ticks_ms()
        for t in self._tasks[:]:
            if time.ticks_diff(now, t['next_run']) >= 0:
                t['callback']()
                if t.get('once'):
                    self._tasks.remove(t)
                else:
                    t['next_run'] = time.ticks_add(now, t['interval'])

